import java.util.HashSet;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        int[] numbers = {1, 2, 2, 3, 3, 3, 4};
        Set<Integer> unique = new HashSet<>();

        for (int n : numbers) {
            unique.add(n);
        }

        System.out.println("Unique count: " + unique.size());
    }
}

